+            } else {
+                agent_session
+                    .agent
+                    .run_continue_with_abort(
+                        None,
+                        make_timeline_callback(Arc::clone(&tl), started_at),
+                    )
+                    .await
+            };
+
+            match result {
+                Ok(message) => {
+                    panic!(
+                        "fatal stream-contract violation should not recover, got {:?}",
+                        message.stop_reason
